// Typed admin API client for building-permit.
// Generated by flowforge JTBD generator — do not edit by hand.
//
// All endpoints are versioned under `/admin` so the host can mount them
// behind a separate ingress with operator MFA at the proxy layer.

const BASE_URL: string =
	(import.meta.env?.VITE_ADMIN_API_BASE_URL as string | undefined) ?? "/admin";

export interface AdminInstance {
	id: string;
	jtbd_id: string;
	state: string;
	tenant_id: string;
	updated_at: string;
}

export interface AdminAuditEntry {
	id: string;
	topic: string;
	tenant_id: string;
	actor: string;
	payload_hash: string;
	prev_hash: string | null;
	created_at: string;
}

export interface AdminAuditChain {
	topic: string;
	verified: boolean;
	entries: ReadonlyArray<AdminAuditEntry>;
	failure_at?: string;
}

export interface AdminSagaStep {
	id: string;
	saga_id: string;
	jtbd_id: string;
	step: string;
	status: "pending" | "compensating" | "compensated" | "failed";
	created_at: string;
}

export interface AdminGrantHistoryEntry {
	id: string;
	tenant_id: string;
	granter: string;
	grantee: string;
	permission: string;
	action: "granted" | "revoked";
	created_at: string;
}

export interface AdminOutboxEnvelope {
	id: string;
	tenant_id: string;
	topic: string;
	attempts: number;
	next_attempt_at: string;
	last_error: string | null;
}

export interface AdminRlsElevation {
	id: string;
	tenant_id: string;
	actor: string;
	scope: string;
	reason: string;
	started_at: string;
	ended_at: string | null;
}

export interface InstanceFilters {
	jtbd?: string;
	state?: string;
	tenant?: string;
}

async function jsonGet<T>(path: string, params?: Record<string, string | undefined>): Promise<T> {
	const url = new URL(`${BASE_URL}${path}`, window.location.origin);
	if (params) {
		for (const [k, v] of Object.entries(params)) {
			if (v !== undefined && v !== "") url.searchParams.set(k, v);
		}
	}
	const res = await fetch(url.toString(), {
		method: "GET",
		credentials: "include",
		headers: { Accept: "application/json" },
	});
	if (!res.ok) {
		throw new Error(`admin API ${path} returned ${res.status}`);
	}
	return (await res.json()) as T;
}

async function jsonPost<T>(path: string, body?: unknown): Promise<T> {
	const url = new URL(`${BASE_URL}${path}`, window.location.origin);
	const res = await fetch(url.toString(), {
		method: "POST",
		credentials: "include",
		headers: {
			Accept: "application/json",
			"Content-Type": "application/json",
		},
		body: body === undefined ? undefined : JSON.stringify(body),
	});
	if (!res.ok) {
		throw new Error(`admin API ${path} returned ${res.status}`);
	}
	return (await res.json()) as T;
}

export const adminApi = {
	listInstances(filters: InstanceFilters): Promise<ReadonlyArray<AdminInstance>> {
		return jsonGet<ReadonlyArray<AdminInstance>>("/instances", {
			jtbd: filters.jtbd,
			state: filters.state,
			tenant: filters.tenant,
		});
	},
	verifyAuditChain(topic: string): Promise<AdminAuditChain> {
		return jsonGet<AdminAuditChain>("/audit", { topic, verify: "true" });
	},
	listPendingSagas(): Promise<ReadonlyArray<AdminSagaStep>> {
		return jsonGet<ReadonlyArray<AdminSagaStep>>("/saga/pending");
	},
	compensateSaga(sagaId: string): Promise<AdminSagaStep> {
		return jsonPost<AdminSagaStep>(`/saga/${encodeURIComponent(sagaId)}/compensate`);
	},
	listGrantHistory(): Promise<ReadonlyArray<AdminGrantHistoryEntry>> {
		return jsonGet<ReadonlyArray<AdminGrantHistoryEntry>>("/grants/history");
	},
	listOutbox(): Promise<ReadonlyArray<AdminOutboxEnvelope>> {
		return jsonGet<ReadonlyArray<AdminOutboxEnvelope>>("/outbox", { status: "pending" });
	},
	retryOutbox(envelopeId: string): Promise<AdminOutboxEnvelope> {
		return jsonPost<AdminOutboxEnvelope>(`/outbox/${encodeURIComponent(envelopeId)}/retry`);
	},
	listRlsElevations(): Promise<ReadonlyArray<AdminRlsElevation>> {
		return jsonGet<ReadonlyArray<AdminRlsElevation>>("/rls/elevations");
	},
};

export const ADMIN_API_BASE_URL = BASE_URL;
